    A = triu(1 + 8*rand(n_sec), 1) + tril(ones(n_sec), -1); 
    A = A ./ A';  
    A(logical(eye(n_sec))) = 1; 
    [V, D] = eig(A); 
    [~, idx] = max(diag(D)); 
    w = V(:, idx)/sum(V(:, idx)); 
    all_weights{k} = w;

