% 4.2 动态规划 
V = zeros(T+1, 1);      % 价值函数 
policy = zeros(T, 1);    % 最优策略 
for t = T:-1:1 
    possible_R = linspace(0, R_total, 100); 
    current_V = -inf(size(possible_R)); 

    for i = 1:length(possible_R) 
        R = possible_R(i);

